def count_distinct_characters(string: str) -> int:
    """ Given a string, find out how many distinct characters (regardless of case) does it consist of
    >>> count_distinct_characters('xyzXYZ')
    3
    >>> count_distinct_characters('Jerry')
    4
    """
    if not string:
        return 0
    return len(set(string.lower()))

def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    return string.swapcase()

def triples_sum_to_zero(l: list):
    """
    triples_sum_to_zero takes a list of integers as an input.
    it returns True if there are three distinct elements in the list that
    sum to zero, and False otherwise.
    """
    if not l or len(l) < 3:
        return False
    arr = sorted(l)
    n = len(arr)
    for i in range(n - 2):
        # Two-pointer approach for the remaining part
        left, right = i + 1, n - 1
        while left < right:
            s = arr[i] + arr[left] + arr[right]
            if s == 0:
                return True
            elif s < 0:
                left += 1
            else:
                right -= 1
    return False

def encode_shift(s: str):
    """
    returns encoded string by shifting every character by 5 in the alphabet.
    """
    return "".join([chr(((ord(ch) + 5 - ord("a")) % 26) + ord("a")) for ch in s])


def decode_shift(s: str):
    """
    takes as input string encoded with encode_shift function. Returns decoded string.
    """
    return "".join([chr(((ord(ch) - 5 - ord("a")) % 26) + ord("a")) for ch in s])

def common(l1: list, l2: list):
    """Return sorted unique common elements for two lists.
    >>> common([1, 4, 3, 34, 653, 2, 5], [5, 7, 1, 5, 9, 653, 121])
    [1, 5, 653]
    >>> common([5, 3, 2, 8], [3, 2])
    [2, 3]
    """
    try:
        return sorted(set(l1) & set(l2))
    except TypeError:
        # Fallback for unhashable elements: use list comprehension and manual dedupe
        seen = set()
        commons = []
        for x in l1:
            if x in l2 and x not in seen:
                seen.add(x)
                commons.append(x)
        try:
            return sorted(commons)
        except TypeError:
            return commons

def correct_bracketing(brackets: str) -> bool:
    """ brackets is a string of "(" and ")".
    return True if every opening bracket has a corresponding closing bracket.
    """
    balance = 0
    for ch in brackets:
        if ch == "(":
            balance += 1
        elif ch == ")":
            if balance == 0:
                return False
            balance -= 1
        else:
            # If unexpected characters appear, treat as invalid
            return False
    return balance == 0

def pluck(arr):
    """
    Return the smallest even value and its first index from arr as [value, index],
    or [] if arr is empty or contains no even numbers.
    """
    if not arr:
        return []
    best_val = None
    best_idx = None
    for i, v in enumerate(arr):
        if isinstance(v, int) and v % 2 == 0:
            if best_val is None or v < best_val:
                best_val = v
                best_idx = i
    if best_val is None:
        return []
    return [best_val, best_idx]

def is_happy(s):
    """You are given a string s.
    Your task is to check if the string is happy or not.
    A string is happy if its length is at least 3 and every 3 consecutive letters are distinct
    """
    if not isinstance(s, str):
        return False
    if len(s) < 3:
        return False
    for i in range(len(s) - 2):
        if len({s[i], s[i+1], s[i+2]}) != 3:
            return False
    return True

def prime_length(string):
    """Write a function that takes a string and returns True if the string
    length is a prime number or False otherwise
    """
    n = len(string)
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    import math
    limit = math.isqrt(n)
    for i in range(3, limit + 1, 2):
        if n % i == 0:
            return False
    return True

def add(lst):
    """Given a non-empty list of integers lst. add the even elements that are at odd indices."""
    return sum(x for i, x in enumerate(lst) if i % 2 == 1 and x % 2 == 0)

def get_row(lst, x):
    res = []
    for i, row in enumerate(lst):
        cols = [j for j, val in enumerate(row) if val == x]
        cols.sort(reverse=True)
        for j in cols:
            res.append((i, j))
    return res

def sort_array(array):
    """
    Given an array of non-negative integers, return a copy of the given array after sorting,
    you will sort the given array in ascending order if the sum( first index value, last index value) is odd,
    or sort it in descending order if the sum( first index value, last index value) is even.

    Note:
    * don't change the given array.
    """
    if not array:
        return []
    total = array[0] + array[-1]
    if total % 2 == 1:
        return sorted(array)
    else:
        return sorted(array, reverse=True)

