def even_odd_palindrome(n):
    """
    Given a positive integer n, return a tuple that has the number of even and odd
    integer palindromes that fall within the range(1, n), inclusive.
    """
    even = 0
    odd = 0
    for i in range(1, n + 1):
        s = str(i)
        if s == s[::-1]:
            if i % 2 == 0:
                even += 1
            else:
                odd += 1
    return (even, odd)

def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the most repetition and containing the corresponding count.
    If several letters have the same occurrence, return all of them.
    """
    if not test:
        return {}
    parts = test.split()
    if not parts:
        return {}
    counts = {}
    for p in parts:
        counts[p] = counts.get(p, 0) + 1
    max_count = max(counts.values())
    return {k: v for k, v in counts.items() if v == max_count}

import heapq

def maximum(arr, k):
    """
    Given an array arr of integers and a positive integer k, return a sorted list 
    of length k with the maximum k numbers in arr.
    """
    if k <= 0:
        return []
    n = len(arr)
    if k >= n:
        return sorted(arr)
    # get k largest (unsorted), then return them sorted in ascending order
    return sorted(heapq.nlargest(k, arr))

def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    try:
        n = abs(int(num))
    except Exception:
        raise ValueError("Input must be an integer")
    if n == 0:
        return (1, 0)
    evens = 0
    odds = 0
    while n:
        d = n % 10
        if d % 2 == 0:
            evens += 1
        else:
            odds += 1
        n //= 10
    return (evens, odds)

import math

def right_angle_triangle(a, b, c):
    '''
    Given the lengths of the three sides of a triangle. Return True if the three
    sides form a right-angled triangle, False otherwise.
    '''
    try:
        sides = sorted((float(a), float(b), float(c)))
    except Exception:
        return False
    x, y, z = sides
    # sides must be positive and satisfy triangle inequality (non-degenerate)
    if x <= 0 or x + y <= z:
        return False
    return math.isclose(x * x + y * y, z * z, rel_tol=1e-9, abs_tol=1e-9)

def eat(number, need, remaining):
    """
    You're a hungry rabbit, and you already have eaten a certain number of carrots,
    but now you need to eat more carrots to complete the day's meals.
    Return [total eaten after your meals, carrots left after your meals].
    """
    if remaining >= need:
        return [number + need, remaining - need]
    else:
        return [number + remaining, 0]

import hashlib

def string_to_md5(text):
    """
    Given a string 'text', return its md5 hash equivalent string.
    If 'text' is an empty string, return None.

    >>> string_to_md5('Hello world') == '3e25960a79dbc69b674cd4ec67a72c62'
    """
    if text == '':
        return None
    if text is None:
        return None
    if not isinstance(text, str):
        text = str(text)
    return hashlib.md5(text.encode('utf-8')).hexdigest()
